17	const PROCESSING_FEE = 5;
18	const BLOCK_SIZE = 3;
19	const RUNE_BLOCK_PREMIUM = 60;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
30	
31	const isRune = (item: Item): boolean => item.type === "rune";
32	
33	const isMainItem = (item: Item): boolean => !isRune(item);
34	
35	const RUNE_UNIT_PRICE = unitPriceFor("rune");
36	
37	const runeBasePremium = (runeCount: number): number =>
38	  runeCount === BLOCK_SIZE ? RUNE_BLOCK_PREMIUM : runeCount * RUNE_UNIT_PRICE;
39	
40	const sumUnitPrices = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);
42	
43	const countRunes = (items: Item[]): number => items.filter(isRune).length;
44	
45	const totalBasePremium = (items: Item[]): number =>
46	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
47	
48	export const quote = (input: QuoteInput): number =>
49	  totalBasePremium(input.items) + PROCESSING_FEE;
50	
51	export const claim = (...args: unknown[]): unknown => {
52	  return undefined; // Not yet implemented
53	};
