function hasEnchantedSword(candidate: Candidate): boolean {
  return (
    candidate.hasSword &&
    (candidate.swordEnchantmentLevel ?? 0) >= SWORD_ENCHANTMENT_THRESHOLD
  );
}

export function claimOffice(candidate: Candidate): number {
  let score = BASE_SCORE;

  if (hasEnchantedSword(candidate)) {
    score += ENCHANTMENT_BONUS;
  }

  return score;
}

